import React, { useEffect, useState } from 'react';
import Input from '../../../components/ui/Input';
import Icon from '../../../components/AppIcon';
import {
  DEPOSIT_TECHNICAL_FEE_RATE,
  PAYMENT_FEE_FIXED,
  PAYMENT_FEE_RATE,
  PLATFORM_COMMISSION_RATE,
  computeOwnerNetEstimate
} from '../../../utils/pricingPolicy';
import {
  CAUTION_MODE_CB,
  CAUTION_MODE_CHEQUE,
  getCautionModeLabel,
  isChequeCautionMode,
  normalizeCautionMode
} from '../../../utils/cautionMode';

// Category parameters (ak, Î²k, mk)
const categoryParams = {
  // Default parameters
  default: { a: 0.11, beta: 0.72, m: 2 }
  // Add specific category parameters here if needed in the future
};

// Normalize category name: lowercase + remove accents + replace non-alphanumeric with _
const normalizeCategory = (category) => {
  if (!category) return '';
  
  return (
    // Remove accents
    (category?.toLowerCase()?.normalize('NFD')?.replace(/[\u0300-\u036f]/g, '')?.replace(/[^a-z0-9]+/g, '_'))
  ); // Replace non-alphanumeric with _
};

// Price simulator formula: P(v,c)
const calculateSuggestedPrice = (value, category) => {
  // Return null for invalid cases
  if (!value || value <= 0 || !isFinite(value)) {
    return null;
  }
  
  const k = normalizeCategory(category);
  
  // Return null for "logements" category
  if (k === 'logements') {
    return null;
  }
  
  // Get category parameters (use default if not specified)
  const params = categoryParams?.[k] || categoryParams?.default;
  const { a, beta, m } = params;
  
  // Calculate components
  const rho = 0.08; // 8% ceiling
  const powerLaw = a * Math.pow(value, beta); // ak * v^Î²k
  const floor = m; // mk minimum
  const ceiling = rho * value; // 8% of value
  
  // Apply formula: round(min(max(powerLaw, floor), ceiling))
  const suggestedPrice = Math.round(Math.min(Math.max(powerLaw, floor), ceiling));
  
  return {
    price: suggestedPrice,
    breakdown: {
      powerLaw: powerLaw?.toFixed(2),
      floor,
      ceiling: ceiling?.toFixed(2)
    }
  };
};

const TarificationStep = ({ formData, updateFormData, errors }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalValue, setModalValue] = useState('');
  const [suggestedPrice, setSuggestedPrice] = useState(null);
  
  // Calculate suggested price when modal value changes
  useEffect(() => {
    if (modalValue && formData?.category) {
      const result = calculateSuggestedPrice(
        parseFloat(modalValue),
        formData?.category
      );
      setSuggestedPrice(result);
    } else {
      setSuggestedPrice(null);
    }
  }, [modalValue, formData?.category]);
  
  // Open modal and pre-fill with equipment value if available
  const openModal = () => {
    setModalValue(formData?.equipmentValue || '');
    setIsModalOpen(true);
  };
  
  // Close modal and reset
  const closeModal = () => {
    setIsModalOpen(false);
    setModalValue('');
    setSuggestedPrice(null);
  };
  
  // Apply suggested price to daily rate and close modal
  const applyPrice = () => {
    if (suggestedPrice?.price) {
      updateFormData('dailyRate', suggestedPrice?.price?.toString());
      // Also save the equipment value used for calculation
      updateFormData('equipmentValue', modalValue);
    }
    closeModal();
  };
  
  // Calculate ROI (weeks and days)
  const calculateROI = () => {
    if (!modalValue || !suggestedPrice?.price) return null;
    const value = parseFloat(modalValue);
    const price = suggestedPrice?.price;
    const daysToAmortize = Math.ceil(value / price);
    const weeksToAmortize = (daysToAmortize / 7)?.toFixed(1);
    return { weeks: weeksToAmortize, days: daysToAmortize };
  };
  
  const roi = calculateROI();
  const simulatedDailyRate = Math.max(0, Number.parseFloat(formData?.dailyRate) || 0);
  const simulatedCautionAmount = Math.max(0, Number.parseFloat(formData?.cautionAmount) || 0);
  const cautionMode = normalizeCautionMode(formData?.cautionMode);
  const cautionByCheque = isChequeCautionMode(cautionMode);
  const simulatedRentalAmount = simulatedDailyRate * 3;
  const simulatedOwnerNet = computeOwnerNetEstimate({
    rentalAmount: simulatedRentalAmount,
    cautionAmount: simulatedCautionAmount,
    applyDepositTechnicalFee: !cautionByCheque
  });

  return (
    <div className="space-y-6">
      <div>
        <h2 className="text-xl font-semibold text-foreground mb-2">Tarification</h2>
        <p className="text-sm text-muted-foreground">Définissez le prix de location et la caution</p>
      </div>
      
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Daily Rate Input with Calculator Button */}
        <div className="md:col-span-2">
          <Input
            label="Tarif journalier"
            type="number"
            placeholder="25.00"
            value={formData?.dailyRate}
            onChange={(e) => updateFormData('dailyRate', e?.target?.value)}
            error={errors?.dailyRate}
            description="Prix par jour de location en euros"
            required
          />
          <button
            type="button"
            onClick={openModal}
            className="mt-2 inline-flex items-center gap-2 px-4 py-2 bg-[#17a2b8] text-white rounded-md text-sm font-medium hover:bg-[#138496] transition-colors"
          >
            <Icon name="Calculator" size={16} />
            Calculer un prix conseillé
          </button>
        </div>

        <Input
          label="Caution demandee"
          type="number"
          placeholder="150.00"
          value={formData?.cautionAmount}
          onChange={(e) => updateFormData('cautionAmount', e?.target?.value)}
          error={errors?.cautionAmount}
          description={cautionByCheque
            ? 'Caution par cheque remise en main propre au proprietaire (verification CNI recommandee).'
            : 'Caution prelevee au paiement, puis remboursee automatiquement a la cloture sans litige.'}
          required
        />

        <div>
          <p className="text-sm font-medium text-foreground mb-2">Mode de caution</p>
          <div className="space-y-2">
            <label className="flex items-start gap-3 p-3 rounded-md border border-border bg-white cursor-pointer">
              <input
                type="radio"
                name="cautionMode"
                value={CAUTION_MODE_CB}
                checked={cautionMode === CAUTION_MODE_CB}
                onChange={(e) => updateFormData('cautionMode', e?.target?.value)}
                className="mt-1"
              />
              <span>
                <span className="block text-sm font-medium text-foreground">{getCautionModeLabel(CAUTION_MODE_CB)}</span>
                <span className="block text-xs text-muted-foreground mt-1">
                  Montant preleve en ligne puis rembourse automatiquement a la cloture sans litige.
                </span>
              </span>
            </label>

            <label className="flex items-start gap-3 p-3 rounded-md border border-border bg-white cursor-pointer">
              <input
                type="radio"
                name="cautionMode"
                value={CAUTION_MODE_CHEQUE}
                checked={cautionMode === CAUTION_MODE_CHEQUE}
                onChange={(e) => updateFormData('cautionMode', e?.target?.value)}
                className="mt-1"
              />
              <span>
                <span className="block text-sm font-medium text-foreground">{getCautionModeLabel(CAUTION_MODE_CHEQUE)}</span>
                <span className="block text-xs text-muted-foreground mt-1">
                  Le cheque de caution est remis au proprietaire a la remise du materiel. Verification CNI recommandee.
                </span>
              </span>
            </label>
          </div>
          {errors?.cautionMode && (
            <p className="text-sm text-destructive mt-2">{errors?.cautionMode}</p>
          )}
        </div>
      </div>
      
      {/* Pricing Tips */}
      <div className="bg-[#17a2b8]/10 border border-[#17a2b8]/20 rounded-lg p-4">
        <div className="flex gap-2">
          <Icon name="Info" size={18} className="text-[#17a2b8] flex-shrink-0 mt-0.5" />
          <div>
            <p className="text-sm font-medium text-foreground mb-2">Conseils de tarification</p>
            <ul className="text-sm text-muted-foreground space-y-1">
              <li>• Consultez les prix similaires dans votre région</li>
              <li>• Tenez compte de l'état et de l'âge du matériel</li>
              <li>• Mode caution choisi: {getCautionModeLabel(cautionMode)}</li>
              {cautionByCheque ? (
                <li>• Cheque de caution: conseillez la verification de la CNI a la remise</li>
              ) : (
                <li>• La caution est prelevee puis remboursee automatiquement en fin de location sans litige</li>
              )}
              <li>• Commission plateforme: {(PLATFORM_COMMISSION_RATE * 100).toLocaleString('fr-FR')}% du montant de location</li>
              <li>• Frais de paiement location: {(PAYMENT_FEE_RATE * 100).toLocaleString('fr-FR')}% + {PAYMENT_FEE_FIXED.toLocaleString('fr-FR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })} EUR (deduits du reversement proprietaire)</li>
              <li>• Frais techniques caution (estimation): {cautionByCheque ? '0%' : `${(DEPOSIT_TECHNICAL_FEE_RATE * 100).toLocaleString('fr-FR')}%`} du montant caution</li>
            </ul>
          </div>
        </div>
      </div>
      
      {/* Earnings Preview */}
      {formData?.dailyRate > 0 && (
        <div className="bg-surface rounded-lg p-4 border border-border">
          <p className="text-sm font-medium text-foreground mb-3">Aperçu des revenus (location de 3 jours)</p>
          <div className="space-y-2 text-sm">
            <div className="flex justify-between">
              <span className="text-muted-foreground">Tarif journalier</span>
              <span className="font-medium text-foreground">{simulatedDailyRate?.toFixed(2)} EUR</span>
            </div>
            <div className="flex justify-between">
              <span className="text-muted-foreground">Total 3 jours</span>
              <span className="font-medium text-foreground">{simulatedRentalAmount?.toFixed(2)} EUR</span>
            </div>
            <div className="flex justify-between text-error">
              <span>Commission plateforme ({(PLATFORM_COMMISSION_RATE * 100).toLocaleString('fr-FR')}%)</span>
              <span>-{simulatedOwnerNet?.platformCommissionAmount?.toFixed(2)} EUR</span>
            </div>
            <div className="flex justify-between text-error">
              <span>Frais paiement location ({(PAYMENT_FEE_RATE * 100).toLocaleString('fr-FR')}% + {PAYMENT_FEE_FIXED.toLocaleString('fr-FR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })} EUR)</span>
              <span>-{simulatedOwnerNet?.paymentProcessingFeeAmount?.toFixed(2)} EUR</span>
            </div>
            <div className="flex justify-between text-error">
              <span>Frais techniques caution ({cautionByCheque ? '0' : (DEPOSIT_TECHNICAL_FEE_RATE * 100).toLocaleString('fr-FR')}%)</span>
              <span>-{simulatedOwnerNet?.cautionTechnicalFeeAmount?.toFixed(2)} EUR</span>
            </div>
            <div className="pt-2 border-t border-border flex justify-between">
              <span className="font-semibold text-foreground">Vous recevez (estimation)</span>
              <span className="font-bold text-success text-lg">{simulatedOwnerNet?.ownerNetEstimate?.toFixed(2)} EUR</span>
            </div>
            <p className="text-xs text-muted-foreground pt-1">
              Estimation hors litige. Les deductions appliquees au reversement proprietaire incluent commission, frais de paiement location et frais techniques caution (mode CB).
            </p>
          </div>
        </div>
      )}
      
      {/* Price Calculator Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-lg shadow-xl max-w-md w-full max-h-[90vh] overflow-y-auto">
            {/* Modal En-tête */}
            <div className="p-6 border-b border-gray-200">
              <div className="flex items-start justify-between">
                <div>
                  <h3 className="text-lg font-semibold text-gray-900">Calculer un prix conseillé</h3>
                  <p className="text-sm text-gray-600 mt-1">
                    Estime un prix par jour à partir de la valeur de l'objet et de la catégorie.
                  </p>
                </div>
                <button
                  type="button"
                  onClick={closeModal}
                  className="text-gray-400 hover:text-gray-600 transition-colors"
                >
                  <Icon name="X" size={20} />
                </button>
              </div>
            </div>
            
            {/* Modal Body */}
            <div className="p-6 space-y-4">
              {/* Value Input */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Valeur de l'objet (EUR)
                </label>
                <input
                  type="number"
                  value={modalValue}
                  onChange={(e) => setModalValue(e?.target?.value)}
                  placeholder="344"
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-[#17a2b8] focus:border-transparent"
                />
              </div>
              
              {/* Category Display */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Catégorie utilisée
                </label>
                <div className="px-3 py-2 bg-gray-100 border border-gray-300 rounded-md text-gray-700">
                  {formData?.category || 'Non définie'}
                </div>
              </div>
              
              {/* Explanation Text */}
              <p className="text-xs text-gray-600 leading-relaxed">
                Basé sur les tendances réelles du site et des partenaires, ce prix reste une recommandation indicative pour t'inspirer sans figer ta stratégie de location.
              </p>
              
              {/* Suggested Price Result */}
              {suggestedPrice && roi && (
                <div className="bg-[#d4f4dd] rounded-lg p-4 space-y-2">
                  <p className="text-xs font-semibold text-gray-700 uppercase tracking-wide">PRIX RECOMMANDÉ</p>
                  <p className="text-3xl font-bold text-gray-900">{suggestedPrice?.price} EUR / jour</p>
                  <p className="text-sm text-gray-700 leading-relaxed">
                    Amorti en environ {roi?.weeks} semaines de location soit après {roi?.days} jours loués.
                  </p>
                </div>
              )}
              
              {/* No Result Message */}
              {modalValue && !suggestedPrice && (
                <div className="bg-yellow-50 border border-yellow-200 rounded-lg p-4">
                  <p className="text-sm text-yellow-800">
                    Impossible de calculer un prix pour cette catégorie ou cette valeur.
                  </p>
                </div>
              )}
            </div>
            
            {/* Modal Footer */}
            <div className="p-6 border-t border-gray-200 flex gap-3 justify-end">
              <button
                type="button"
                onClick={closeModal}
                className="px-4 py-2 text-gray-700 bg-white border border-gray-300 rounded-md text-sm font-medium hover:bg-gray-50 transition-colors"
              >
                Annuler
              </button>
              <button
                type="button"
                onClick={applyPrice}
                disabled={!suggestedPrice}
                className="px-4 py-2 bg-gray-900 text-white rounded-md text-sm font-medium hover:bg-gray-800 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
              >
                Appliquer ce prix
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default TarificationStep;

